// v2.5: Pâ”ĽĂ–â”śĹźmâ”śĂ­ kontrola charger_state - "2" = Charging, "3" = Charged, jinak = idle
var chargerState = getState("sensor.charger_state_garage") || "0";
var chargerCharged = (chargerState === "3" || chargerState === "4");  // 3=Charged, 4=Error/Done

// OPRAVA: â”€Ĺąâ”śĹźst forecast Pâ”ĽĹ›â”śĹąMO z HA entity (ne z fve_config!)
var vyrobaDnes   = getFloat("input_number.predpoved_solarni_vyroby_dnes", 0);
