// 1. Auto nemâ”śĂ­ hlad Ă”Ä‡Äş stop (grid+solar OFF)
if (!autoHlad) {
    node.status({fill:"grey", shape:"ring", text:"Nemâ”śĂ­ hlad Ă”Ä‡Äş stop"});
    return [[msg], null, null];
}

// 1b. v2.5: Charger hlâ”śĂ­sâ”śĹź "charged" Ă”Ä‡Äş stop okamâ”ĽĹĽitâ”€Ĺ¤ (bez â”€Ĺąekâ”śĂ­nâ”śĹź na auto_ma_hlad delay)
if (chargerCharged) {
    node.status({fill:"grey", shape:"ring", text:"Charger state=" + chargerState + " (nabito) Ă”Ä‡Äş stop"});
    return [[msg], null, null];
}

// 2. Automatizace vypnuta Ă”Ä‡Äş stop
if (!automatizace) {
    node.status({fill:"grey", shape:"ring", text:"Automatizace OFF Ă”Ä‡Äş stop"});
    return [[msg], null, null];
}

// 3. MUTEX: NIBE topâ”śĹź Ă”Ä‡Äş auto NESMâ”śĹą nabâ”śĹźjet (nikdy souâ”€Ĺąasnâ”€Ĺ¤!)
var ultraLevna = global.get("ultra_levna_energie") || false;
var cerpadloTopi = global.get("cerpadlo_topi") || false;
if (cerpadloTopi && !ultraLevna) {
    node.status({fill:"red", shape:"ring", text:"Ă”ĂśĂˇÂ´ĹžÄ†MUTEX: NIBE topâ”śĹź Ă”Ä‡Äş auto STOP"});
    return [[msg], null, null];
}

// 3b. SOC pod prahem pro solâ”śĂ­rnâ”śĹź nabâ”śĹźjenâ”śĹź Ă”Ä‡Äş stop solâ”śĂ­rnâ”śĹź cyklus
if (batSoc < MIN_SOC_SLUNCE) {
    node.status({fill:"orange", shape:"ring", text:"SOC " + batSoc + "% < " + MIN_SOC_SLUNCE + "% Ă”Ä‡Äş stop"});
    return [[msg], null, null];
}

// === v2.4: Pokud solâ”śĂ­rnâ”śĹź cyklus Uâ”ĽĹ» Bâ”€Ăśâ”ĽĹ»â”śĹą, nechat ho bâ”€Ĺ¤â”ĽĹĽet ===
// Cyklus si sâ”śĂ­m â”ĽĂ–â”śĹźdâ”śĹź ampâ”śÄ™râ”śĂ­â”ĽĹĽ a zastavâ”śĹź se kdyâ”ĽĹĽ target < 6A
// Manager ho nezastavuje kvâ”ĽÂ»li poklesu pâ”ĽĂ–ebytku
if (solarCyklusBezi) {
    node.status({fill:"green", shape:"dot", text:"Ă”Ĺ›Ă‡Â´ĹžÄ† Cyklus bâ”€Ĺ¤â”ĽĹĽâ”śĹź | SOC:" + batSoc + "% pâ”ĽĂ–ebytek:" + Math.round(rozdiVyroby) + "W charger:" + chargerState});
