}

// === Novâ”śĹ» start solâ”śĂ­rnâ”śĹźho nabâ”śĹźjenâ”śĹź ===
var maPrebytek = rozdiVyroby > MIN_SOLAR_W;

// 4. Solâ”śĂ­rnâ”śĹź reâ”ĽĹĽim ON Ă”Ä‡Äş slunce (jen pokud je pâ”ĽĂ–ebytek)
if (solarniRezim && maPrebytek) {
