    return [null, [msg], null];
}

// 5. Letnâ”śĹź reâ”ĽĹĽim + pâ”ĽĂ–ebytek Ă”Ä‡Äş slunce
if (letniRezim && maPrebytek) {
    node.status({fill:"green", shape:"dot", text:"Letnâ”śĹź + pâ”ĽĂ–ebytek=" + Math.round(rozdiVyroby) + "W Ă”Ä‡Äş slunce"});
    return [null, [msg], null];
}

// 6. Vâ”śĹ»roba dnes > FORECAST + pâ”ĽĂ–ebytek Ă”Ä‡Äş slunce
if (vyrobaDnes > FORECAST_KWH && maPrebytek) {
