node.status({fill:"blue", shape:"dot", text:"Sâ”śĹźâ”ĽÄ… | dnes:" + Math.round(vyrobaDnes) + " zâ”śĹźtra:" + Math.round(vyrobaZitra) + " bat:" + batSoc + "%"});
